#!/bin/bash
set -e
pushd "$(dirname "$0")" > /dev/null
# Keep existing state-visualization images if regeneration fails.
# Only clear files that are always regenerated by the benchmark runner.
rm -f results/benchmark_results.json results/comparison.png
python run_benchmarks.py --dv-qubits 4 --cvdv-cv-qubits 10 12 14 --bosonic-cv-qubits 5 6 7 --runs 10
popd > /dev/null